  "mainEntity": {
    "@type": "FAQPage",
    "mainEntity": [
      {
        "@type": "Question",
        "name": "What should I do if I have concerns about my matter?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "If you are a client of Blacks and have concerns over how your matter is being dealt with, or over the service which you are receiving, please raise this in the first instance with the person who has day‑to‑day responsibility for your matter, or with the Partner in charge of the file. Please provide them with full details of your concerns over the telephone, in writing, or at a meeting. A note will be taken of the issues raised, which will be investigated with a view to resolving the matter to your satisfaction."
        }
      },
      {
        "@type": "Question",
        "name": "How do I make a formal complaint?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "If we are unable to resolve your concerns to your satisfaction via the team dealing with the matter, you should raise a formal complaint which will be dealt with and investigated by our dedicated Complaints Team at complaints@lawblacks.com."
        }
      },
      {
        "@type": "Question",
        "name": "What is your complaints procedure?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "We will acknowledge your complaint within two working days following the date of receipt. We will then investigate your complaint and provide you with a formal response, usually within 14 working days. If you are not satisfied with our formal response, you can ask that the matter is escalated for a final review within 35 days. On escalation, the complaint will be reviewed independently by the Firm's Head of Compliance or by a Partner of the Firm, and our Final Response will be provided within 14 working days from the date of receipt of your request for escalation."
        }
      },
      {
        "@type": "Question",
        "name": "Can I contact the Legal Ombudsman?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "If you are not satisfied with our Final Response and any remedial action being taken or proposed, you can contact the Legal Ombudsman service. The Legal Ombudsman expects complaints to be made within one year of the date of the act or omission about which you are concerned, or within one year of you realising there was a concern. You must also refer your concerns to the Legal Ombudsman within six months of our final response to you. Contact them at Enquiries@LegalOmbudsman.org.uk or www.LegalOmbudsman.org.uk."
        }
      },
      {
        "@type": "Question",
        "name": "What if I am not a client but want to make a complaint?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "If you are not a client of MOONSTONE ADVOCATES but have a complaint to make where Blacks are acting for another party in the transaction or matter, your appropriate course of action is to raise your concerns with your appointed legal representative. If you are not using your own solicitors, we will only be able to consider your complaint if you are alleging that Blacks have acted in breach of any of the principles or outcomes provided for in the SRA Standards and Regulations. Contact complaints@lawblacks.com."
        }
      },
      {
        "@type": "Question",
        "name": "Will I be charged for making a complaint?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "We will not charge you for handling your complaint."
        }
      }
    ]
  }
